
"use client"

import { useState, useEffect, useMemo } from "react";
import { useParams, useRouter } from "next/navigation";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Settings, Share2, MapPin, Loader2, Edit3, Check, UserCircle, Car, Gauge, Cpu, Zap, ChevronLeft, Trash2, AlertTriangle } from "lucide-react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter } from "@/components/ui/dialog";
import { 
  AlertDialog, 
  AlertDialogAction, 
  AlertDialogCancel, 
  AlertDialogContent, 
  AlertDialogDescription, 
  AlertDialogFooter, 
  AlertDialogHeader, 
  AlertDialogTitle, 
  AlertDialogTrigger 
} from "@/components/ui/alert-dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useUser, useDoc, useFirestore, useMemoFirebase, updateDocumentNonBlocking, useCollection, deleteDocumentNonBlocking } from "@/firebase";
import { doc, collection, query, orderBy, limit, getDocs, where } from "firebase/firestore";
import { useToast } from "@/hooks/use-toast";
import { cn } from "@/lib/utils";
import { RenderCarIcon, CarIconType } from "@/components/icons/car-icons";

const KOSOVO_CITIES = [
  "Prishtinë", "Prizren", "Pejë", "Gjakovë", "Mitrovicë", "Gjilan", "Ferizaj", 
  "Vushtrri", "Podujevë", "Rahovec", "Fushë Kosovë", "Suharekë", "Kaçanik", 
  "Skënderaj", "Lipjan", "Malishevë", "Drenas", "Deçan", "Klinë", "Kamenicë", 
  "Dragash", "Istog", "Viti", "Obiliq", "Leposaviq", "Graçanicë", "Hani i Elezit", 
  "Zveçan", "Shtime", "Novobërdë", "Zubin Potok", "Junik", "Mamushë", 
  "Ranillug", "Partesh", "Kllokot"
];

const ICON_LIST: { id: CarIconType; label: string }[] = [
  { id: 'turbo', label: 'Turbo' },
  { id: 'speedometer', label: 'Gauge' },
  { id: 'crown', label: 'King' },
  { id: 'lightning', label: 'Bolt' },
  { id: 'shield', label: 'Pro' },
  { id: 'flame', label: 'Fire' },
];

export default function ProfileViewPage() {
  const params = useParams();
  const router = useRouter();
  const targetUserId = params.userId as string;
  const { user: currentUser } = useUser();
  const isOwnProfile = currentUser?.uid === targetUserId;
  const db = useFirestore();
  const { toast } = useToast();
  
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);
  const [isResetting, setIsResetting] = useState(false);
  const [formData, setFormData] = useState({
    username: "",
    city: "",
    carBrand: "",
    carModel: "",
    horsepower: 0,
    modifications: "",
    profileIcon: "speedometer" as CarIconType,
  });

  const profileRef = useMemoFirebase(() => {
    if (!targetUserId || !db) return null;
    return doc(db, "users", targetUserId);
  }, [targetUserId, db]);

  const { data: profile, isLoading: isProfileLoading } = useDoc(profileRef);

  // Fetch runs to calculate stats
  const runsQuery = useMemoFirebase(() => {
    if (!targetUserId || !db) return null;
    return query(
      collection(db, "users", targetUserId, "runs"),
      orderBy("createdAt", "desc")
    );
  }, [targetUserId, db]);

  const { data: runs } = useCollection(runsQuery);

  const stats = useMemo(() => {
    if (!runs) return { totalRuns: 0, totalKm: "0.00", peak: 0 };
    const totalDistance = runs.reduce((acc, run) => acc + (run.distanceMeters || 0), 0);
    const peakSpeed = runs.reduce((max, run) => Math.max(max, run.peakSpeedKmH || 0), 0);
    return {
      totalRuns: runs.length,
      totalKm: (totalDistance / 1000).toFixed(2),
      peak: peakSpeed
    };
  }, [runs]);

  useEffect(() => {
    if (profile && isOwnProfile) {
      setFormData({
        username: profile.username || "",
        city: profile.city || "Prishtinë",
        carBrand: profile.carBrand || "",
        carModel: profile.carModel || "",
        horsepower: profile.horsepower || 0,
        modifications: profile.modifications || "",
        profileIcon: (profile.profileIcon as CarIconType) || "speedometer",
      });
    }
  }, [profile, isOwnProfile]);

  const handleSaveProfile = () => {
    if (!profileRef || !isOwnProfile) return;

    const updatedData = {
      ...formData,
      horsepower: Number(formData.horsepower),
      updatedAt: new Date().toISOString(),
    };

    updateDocumentNonBlocking(profileRef, updatedData);
    toast({ title: "Profili u përditësua", description: "Të dhënat u ruajtën me sukses." });
    setIsEditDialogOpen(false);
  };

  const handleResetStats = async () => {
    if (!db || !targetUserId || !isOwnProfile) return;
    setIsResetting(true);
    
    try {
      // 1. Delete from user's local runs
      const userRunsRef = collection(db, "users", targetUserId, "runs");
      const userRunsSnap = await getDocs(userRunsRef);
      userRunsSnap.forEach((d) => {
        deleteDocumentNonBlocking(doc(db, "users", targetUserId, "runs", d.id));
      });

      // 2. Delete from public runs (rankings)
      const publicRunsRef = collection(db, "public_runs");
      const q = query(publicRunsRef, where("userId", "==", targetUserId));
      const publicRunsSnap = await getDocs(q);
      publicRunsSnap.forEach((d) => {
        deleteDocumentNonBlocking(doc(db, "public_runs", d.id));
      });

      toast({
        title: "Statistikat u resetuan",
        description: "Të gjitha të dhënat dhe rekordet në ranking janë fshirë.",
      });
      setIsEditDialogOpen(false);
    } catch (error) {
      console.error("Error resetting stats:", error);
      toast({
        variant: "destructive",
        title: "Gabim",
        description: "Dështoi resetimi i statistikave. Provoni përsëri.",
      });
    } finally {
      setIsResetting(false);
    }
  };

  if (isProfileLoading) {
    return (
      <div className="flex flex-col min-h-screen bg-background items-center justify-center">
        <Loader2 className="w-10 h-10 text-accent animate-spin" />
      </div>
    );
  }

  if (!profile) {
    return (
      <div className="flex flex-col min-h-screen bg-background items-center justify-center p-8 text-center">
        <UserCircle className="w-16 h-16 text-muted-foreground mb-4 opacity-20" />
        <h1 className="text-xl font-black uppercase italic">Përdoruesi nuk u gjet</h1>
        <Button onClick={() => router.back()} variant="ghost" className="mt-4 text-accent uppercase font-black italic">KTHEHU</Button>
      </div>
    );
  }

  return (
    <div className="flex flex-col min-h-screen bg-background text-foreground pb-24 overflow-x-hidden no-scrollbar">
      <div className="p-6 flex justify-between items-center z-20">
        <div className="flex items-center gap-2">
           <Button onClick={() => router.back()} size="icon" variant="ghost" className="rounded-xl hover:bg-white/5 mr-1"><ChevronLeft className="w-6 h-6" /></Button>
           <h1 className="text-xl font-black italic uppercase tracking-tighter">PROFILI</h1>
        </div>
        <div className="flex gap-2">
          {isOwnProfile && (
            <Dialog open={isEditDialogOpen} onOpenChange={setIsEditDialogOpen}>
              <DialogTrigger asChild>
                <Button size="icon" variant="outline" className="rounded-xl glass border-white/10 w-10 h-10">
                  <Settings className="w-4 h-4" />
                </Button>
              </DialogTrigger>
              <DialogContent className="glass border-white/10 text-foreground sm:max-w-[425px] max-h-[90vh] overflow-y-auto no-scrollbar rounded-[2.5rem]">
                <DialogHeader><DialogTitle className="text-xl font-black italic uppercase tracking-tighter">Ndrysho Profilin</DialogTitle></DialogHeader>
                <div className="grid gap-6 py-4">
                  <div className="grid gap-2">
                    <Label htmlFor="username" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Emri i Përdoruesit</Label>
                    <Input id="username" value={formData.username} onChange={(e) => setFormData({...formData, username: e.target.value})} className="bg-white/5 border-white/10 rounded-xl" />
                  </div>
                  <div className="grid gap-3">
                    <Label className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Zgjidh Distinktivin</Label>
                    <div className="grid grid-cols-3 gap-3">
                      {ICON_LIST.map((item) => (
                        <button key={item.id} onClick={() => setFormData({...formData, profileIcon: item.id})} className={cn("relative aspect-square rounded-2xl flex flex-col items-center justify-center border-2 transition-all p-2", formData.profileIcon === item.id ? "border-accent bg-accent/10 shadow-[0_0_15px_rgba(77,224,244,0.3)]" : "border-white/5 bg-white/[0.02] opacity-60 hover:opacity-100")}>
                          <RenderCarIcon type={item.id} className={cn("w-8 h-8", formData.profileIcon === item.id ? "text-accent" : "text-white/60")} />
                          <span className="text-[8px] font-black uppercase mt-2 tracking-widest">{item.label}</span>
                        </button>
                      ))}
                    </div>
                  </div>
                  <div className="grid gap-2">
                    <Label htmlFor="city" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Qyteti i Kosovës</Label>
                    <Select value={formData.city} onValueChange={(value) => setFormData({...formData, city: value})}><SelectTrigger className="bg-white/5 border-white/10 rounded-xl h-12"><SelectValue placeholder="Zgjidh qytetin" /></SelectTrigger>
                      <SelectContent className="glass border-white/10 max-h-[300px]">{KOSOVO_CITIES.map((city) => (<SelectItem key={city} value={city} className="font-bold text-xs uppercase italic">{city}</SelectItem>))}</SelectContent>
                    </Select>
                  </div>
                  <div className="grid gap-4">
                    <div className="grid gap-2">
                      <Label htmlFor="carBrand" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Marka</Label>
                      <Input id="carBrand" value={formData.carBrand} onChange={(e) => setFormData({...formData, carBrand: e.target.value})} className="bg-white/5 border-white/10 rounded-xl" />
                    </div>
                    <div className="grid gap-2">
                      <Label htmlFor="carModel" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Modeli</Label>
                      <Input id="carModel" value={formData.carModel} onChange={(e) => setFormData({...formData, carModel: e.target.value})} className="bg-white/5 border-white/10 rounded-xl" />
                    </div>
                  </div>
                  <div className="grid gap-2">
                    <Label htmlFor="horsepower" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">HP</Label>
                    <Input id="horsepower" type="number" value={formData.horsepower} onChange={(e) => setFormData({...formData, horsepower: parseInt(e.target.value) || 0})} className="bg-white/5 border-white/10 rounded-xl" />
                  </div>
                  <div className="grid gap-2">
                    <Label htmlFor="modifications" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Modifikimet</Label>
                    <Textarea id="modifications" value={formData.modifications} onChange={(e) => setFormData({...formData, modifications: e.target.value})} className="bg-white/5 border-white/10 rounded-xl min-h-[80px]" />
                  </div>

                  {/* Danger Zone */}
                  <div className="mt-4 pt-4 border-t border-white/5">
                    <Label className="text-[10px] font-bold uppercase tracking-widest text-red-500 mb-3 block">ZONA E RREZIKUT</Label>
                    <AlertDialog>
                      <AlertDialogTrigger asChild>
                        <Button variant="outline" className="w-full h-12 border-red-500/20 bg-red-500/5 hover:bg-red-500/10 text-red-500 rounded-xl font-bold uppercase italic text-[10px]">
                          <Trash2 className="w-3.5 h-3.5 mr-2" /> RESETO TË GJITHA STATISTIKAT
                        </Button>
                      </AlertDialogTrigger>
                      <AlertDialogContent className="glass border-white/10 rounded-[2rem]">
                        <AlertDialogHeader>
                          <AlertDialogTitle className="text-lg font-black uppercase italic tracking-tighter text-white">A jeni të sigurt?</AlertDialogTitle>
                          <AlertDialogDescription className="text-xs font-medium text-muted-foreground leading-relaxed">
                            Ky veprim do të fshijë përgjithmonë të gjitha garat tuaja (Runs) dhe do t'ju largojë nga të gjitha tabelat e Ranking-ut. Ky veprim nuk mund të kthehet prapa.
                          </AlertDialogDescription>
                        </AlertDialogHeader>
                        <AlertDialogFooter className="mt-4">
                          <AlertDialogCancel className="rounded-xl border-white/10 font-bold uppercase italic text-[10px]">ANULO</AlertDialogCancel>
                          <AlertDialogAction 
                            onClick={handleResetStats} 
                            disabled={isResetting}
                            className="bg-red-600 hover:bg-red-700 text-white rounded-xl font-bold uppercase italic text-[10px]"
                          >
                            {isResetting ? <Loader2 className="w-3 h-3 animate-spin" /> : "PO, RESETO TANI"}
                          </AlertDialogAction>
                        </AlertDialogFooter>
                      </AlertDialogContent>
                    </AlertDialog>
                  </div>
                </div>
                <DialogFooter className="pt-4"><Button onClick={handleSaveProfile} className="w-full bg-accent text-background font-black italic uppercase rounded-2xl h-14 shadow-xl neon-glow">RUAJ NDRYSHIMET</Button></DialogFooter>
              </DialogContent>
            </Dialog>
          )}
          <Button size="icon" variant="outline" className="rounded-xl glass border-white/10 w-10 h-10"><Share2 className="w-4 h-4" /></Button>
        </div>
      </div>

      <div className="px-6 py-4 relative z-10 flex flex-col items-center text-center">
        <div className="relative w-40 h-40 mb-6">
          <div className="absolute inset-0 rounded-[2.5rem] bg-gradient-to-br from-accent to-blue-600 animate-pulse opacity-20 blur-xl" />
          <div className="relative w-full h-full rounded-[2.5rem] bg-zinc-950 border-4 border-white/5 shadow-2xl flex items-center justify-center overflow-hidden">
            <RenderCarIcon type={profile?.profileIcon} className="w-20 h-20 text-accent drop-shadow-[0_0_10px_rgba(77,224,244,0.5)]" />
          </div>
          {profile?.isPremium && (
            <div className="absolute -bottom-2 -right-2 bg-accent text-background rounded-full p-2 border-4 border-background shadow-lg">
              <Check className="w-4 h-4" />
            </div>
          )}
        </div>

        <div className="space-y-2">
          <h1 className="text-3xl font-black italic tracking-tighter uppercase leading-none">{profile?.username}</h1>
          <div className="flex items-center justify-center gap-2">
            <Badge variant="outline" className="bg-accent/10 border-accent/20 text-accent font-black px-4 py-1 rounded-full text-[10px]">
              {profile?.isPremium ? 'PREMIUM' : 'SHOFER KOSOVAR'}
            </Badge>
            <div className="flex items-center gap-1.5 text-[10px] font-black text-muted-foreground uppercase bg-white/5 px-4 py-1 rounded-full border border-white/5">
              <MapPin className="w-3.5 h-3.5 text-accent" />
              {profile?.city}
            </div>
          </div>
        </div>

        <div className="flex gap-3 w-full mt-8">
          {[
            { label: "Km Total", val: stats.totalKm },
            { label: "Gara", val: stats.totalRuns.toString() },
            { label: "Peak", val: `${stats.peak} km/h`, accent: true }
          ].map((stat, i) => (
            <div key={i} className="flex-1 glass rounded-[1.8rem] p-4 border-white/5 flex flex-col items-center">
              <p className="text-[9px] font-black text-muted-foreground uppercase tracking-widest mb-1">{stat.label}</p>
              <p className={cn("text-xl font-black italic", stat.accent && "text-accent")}>{stat.val}</p>
            </div>
          ))}
        </div>
      </div>

      <div className="px-6 mt-6 space-y-4">
        <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground px-1">DETAJET E MJETIT</h2>
        <Card className="glass border-accent/20 p-7 rounded-[2.5rem] space-y-6 relative overflow-hidden group shadow-2xl">
          <div className="relative z-10 flex flex-col gap-1">
            <div className="flex items-center gap-3">
              <div className="w-1.5 h-10 bg-accent rounded-full neon-glow" />
              <div>
                <h3 className="text-3xl font-black italic text-white uppercase tracking-tighter leading-none mb-1">{profile?.carBrand}</h3>
                <p className="text-lg font-black italic text-accent/80 uppercase tracking-tighter leading-none">{profile?.carModel}</p>
              </div>
            </div>
            <div className="mt-4 flex items-center gap-2">
              <Badge className="bg-white/5 border-white/10 text-accent font-black text-[9px] px-3 py-1 rounded-lg"><Cpu className="w-3 h-3 mr-1.5" />{profile?.horsepower} HP</Badge>
            </div>
          </div>
          <div className="relative z-10 grid grid-cols-3 gap-4 pt-8 border-t border-white/10">
            {[ { label: "0-100", val: "--", unit: "sek", icon: Zap }, { label: "100-200", val: "--", unit: "sek", icon: Gauge }, { label: "TOP SPEED", val: `${stats.peak}`, unit: "km/h", icon: Car } ].map((stat, i) => (
              <div key={i} className="text-center group/stat">
                <p className="text-[9px] font-black text-muted-foreground uppercase tracking-widest mb-3 group-hover/stat:text-accent transition-colors flex items-center justify-center gap-1.5">
                  <stat.icon className="w-2.5 h-2.5" />{stat.label}
                </p>
                <div className="flex flex-col items-center">
                  <span className="text-2xl font-black italic text-white leading-none tracking-tighter tabular-nums mb-1">{stat.val}</span>
                  <span className="text-[8px] font-black text-accent uppercase tracking-widest">{stat.unit}</span>
                </div>
              </div>
            ))}
          </div>
        </Card>

        <div className="glass rounded-[2rem] p-6 border-white/5 space-y-4 shadow-xl">
          <h4 className="text-[10px] font-black text-accent uppercase tracking-widest flex items-center gap-2 mb-2"><Zap className="w-3.5 h-3.5" />MODIFIKIMET</h4>
          <div className="flex flex-wrap gap-2">
            {profile?.modifications ? profile.modifications.split(',').map((mod: string, i: number) => (
              <Badge key={i} variant="outline" className="bg-white/5 border-white/10 text-[10px] font-black italic py-2 px-4 rounded-xl uppercase tracking-tighter">{mod.trim()}</Badge>
            )) : <p className="text-[11px] font-bold text-muted-foreground italic uppercase tracking-widest px-1">Nuk ka modifikime</p>}
          </div>
        </div>
      </div>
      <BottomNav />
    </div>
  );
}
